#!/usr/bin/env -S npx ts-node -r tsconfig-paths/register
/**
 * Example: Azure CLI Authentication
 *
 * Description: Automatically use credentials from Azure CLI. Best for local
 * development on Azure.
 *
 * Prerequisites:
 * - Azure CLI installed
 * - Logged in: `az login`
 * - Databricks workspace on Azure
 *
 * Setup:
 * ```bash
 * az login
 * az account set --subscription <subscription-id>
 * ```
 *
 * Run:
 * ```bash
 * DATABRICKS_HOST="https://adb-<workspace-id>.<random>.azuredatabricks.net" \
 * npx ts-node examples/auth/azure-cli.ts
 * ```
 */

import {Config, WorkspaceClient} from "@databricks/sdk-experimental";

async function main() {
    const config = new Config({
        host: process.env.DATABRICKS_HOST,
        authType: "azure-cli",
    });

    const client = new WorkspaceClient(config);

    try {
        const user = await client.currentUser.me();
        console.log(
            `✓ Successfully authenticated via Azure CLI as: ${user.userName}`
        );
        console.log(`  User ID: ${user.id}`);

        console.log(`  Host: ${config.host}`);
    } catch (error) {
        console.error("✗ Authentication failed:", error);
        console.error("\nMake sure you have:");
        console.error("  1. Set DATABRICKS_HOST environment variable");
        console.error("  2. Logged in with: az login");
        console.error(
            "  3. Set correct subscription: az account set --subscription <id>"
        );
        process.exit(1);
    }
}

main().catch(console.error);
